-- Simple XML parser that handles entity references, CDATA, and basic XML structures
-- Designed for SOAP API gateway use in OpenResty

local XmlParser = {}
XmlParser.__index = XmlParser

-- Entity reference map (standard + common custom entities)
local entity_map = {
    ["&lt;"]   = "<",
    ["&gt;"]   = ">",
    ["&amp;"]  = "&",
    ["&apos;"] = "'",
    ["&quot;"] = '"',
}

local function resolve_entities(text)
    if not text then return nil end
    -- Resolve numeric character references
    text = text:gsub("&#(%d+);", function(n)
        return string.char(tonumber(n))
    end)
    text = text:gsub("&#x(%x+);", function(n)
        return string.char(tonumber(n, 16))
    end)
    -- Resolve named entity references
    text = text:gsub("(&%a+;)", function(entity)
        return entity_map[entity] or entity
    end)
    return text
end

local function strip_namespace(tag)
    local stripped = tag:match(":(.+)$")
    return stripped or tag
end

local function trim(s)
    if not s then return nil end
    return s:match("^%s*(.-)%s*$")
end

local function parse_attributes(attr_string)
    local attrs = {}
    if not attr_string or attr_string == "" then
        return attrs
    end
    for key, value in attr_string:gmatch('([%w_:%-]+)%s*=%s*"([^"]*)"') do
        attrs[key] = resolve_entities(value)
    end
    for key, value in attr_string:gmatch("([%w_:%-]+)%s*=%s*'([^']*)'") do
        attrs[key] = resolve_entities(value)
    end
    return attrs
end

local function parse_xml(xml_string)
    if not xml_string or xml_string == "" then
        return nil, "empty XML input"
    end

    -- Remove XML declaration
    xml_string = xml_string:gsub("<%?xml.-%?>", "")

    -- Remove comments
    xml_string = xml_string:gsub("<!%-%-.-%--%>", "")

    -- Handle CDATA sections by replacing them with resolved text
    xml_string = xml_string:gsub("<!%[CDATA%[(.-)%]%]>", function(content)
        -- Escape special XML chars in CDATA content so they survive parsing
        content = content:gsub("&", "&amp;")
        content = content:gsub("<", "&lt;")
        content = content:gsub(">", "&gt;")
        return content
    end)

    local stack = {}
    local root = { tag = "_root", children = {}, attrs = {} }
    local current = root

    table.insert(stack, current)

    local pos = 1
    while pos <= #xml_string do
        local start_open, end_open, tag_content = xml_string:find("<([^>]+)>", pos)
        if not start_open then
            -- Remaining text
            local text_content = trim(resolve_entities(xml_string:sub(pos)))
            if text_content and text_content ~= "" then
                current.text = (current.text or "") .. text_content
            end
            break
        end

        -- Text before this tag
        if start_open > pos then
            local text_content = trim(resolve_entities(xml_string:sub(pos, start_open - 1)))
            if text_content and text_content ~= "" then
                current.text = (current.text or "") .. text_content
            end
        end

        tag_content = trim(tag_content)

        if tag_content:sub(1, 1) == "/" then
            -- Closing tag
            table.remove(stack)
            current = stack[#stack]
        elseif tag_content:sub(-1) == "/" then
            -- Self-closing tag
            local tag_name, attr_string = tag_content:sub(1, -2):match("^(%S+)%s*(.*)")
            tag_name = trim(tag_name)
            local node = {
                tag = tag_name,
                tag_local = strip_namespace(tag_name),
                attrs = parse_attributes(attr_string),
                children = {},
                text = nil,
            }
            table.insert(current.children, node)
        else
            -- Opening tag
            local tag_name, attr_string = tag_content:match("^(%S+)%s*(.*)")
            tag_name = trim(tag_name)
            local node = {
                tag = tag_name,
                tag_local = strip_namespace(tag_name),
                attrs = parse_attributes(attr_string),
                children = {},
                text = nil,
            }
            table.insert(current.children, node)
            table.insert(stack, node)
            current = node
        end

        pos = end_open + 1
    end

    if #root.children == 0 then
        return nil, "no root element found"
    end

    return root.children[1], nil
end

-- Utility: Find a child element by local name (ignoring namespace prefix)
local function find_child(node, local_name)
    if not node or not node.children then return nil end
    for _, child in ipairs(node.children) do
        if child.tag_local == local_name then
            return child
        end
    end
    return nil
end

-- Utility: Find all children by local name
local function find_children(node, local_name)
    local results = {}
    if not node or not node.children then return results end
    for _, child in ipairs(node.children) do
        if child.tag_local == local_name then
            table.insert(results, child)
        end
    end
    return results
end

-- Utility: Recursively find a descendant by local name (depth-first)
local function find_descendant(node, local_name)
    if not node or not node.children then return nil end
    for _, child in ipairs(node.children) do
        if child.tag_local == local_name then
            return child
        end
        local found = find_descendant(child, local_name)
        if found then return found end
    end
    return nil
end

-- Utility: Convert XML node to a Lua table (recursive)
local function node_to_table(node)
    if not node then return nil end

    -- Leaf node with only text
    if #node.children == 0 then
        return node.text
    end

    local result = {}

    -- Check if there are repeated child tag names (array-like)
    local tag_counts = {}
    for _, child in ipairs(node.children) do
        local name = child.tag_local
        tag_counts[name] = (tag_counts[name] or 0) + 1
    end

    for _, child in ipairs(node.children) do
        local name = child.tag_local
        local value = node_to_table(child)

        if tag_counts[name] > 1 then
            -- Multiple children with same name -> array
            if not result[name] then
                result[name] = {}
            end
            table.insert(result[name], value)
        else
            result[name] = value
        end
    end

    return result
end

-- Extract SOAP envelope components
local function parse_soap_envelope(root)
    local envelope = {}

    if root.tag_local ~= "Envelope" then
        return nil, "root element is not a SOAP Envelope, got: " .. (root.tag_local or "nil")
    end

    -- Extract SOAP Header
    local header_node = find_child(root, "Header")
    if header_node then
        envelope.header = node_to_table(header_node)
        envelope.header_node = header_node
    end

    -- Extract SOAP Body
    local body_node = find_child(root, "Body")
    if not body_node then
        return nil, "SOAP Body not found in Envelope"
    end

    envelope.body_node = body_node
    envelope.body = node_to_table(body_node)

    -- Extract the operation (first child of Body)
    if body_node.children and #body_node.children > 0 then
        local operation_node = body_node.children[1]
        envelope.operation = operation_node.tag_local
        envelope.operation_node = operation_node
        envelope.operation_data = node_to_table(operation_node)
    end

    -- Check for SOAP Fault
    local fault_node = find_child(body_node, "Fault")
    if fault_node then
        envelope.fault = node_to_table(fault_node)
        envelope.is_fault = true
    else
        envelope.is_fault = false
    end

    return envelope, nil
end

-- Build a SOAP fault response XML string
local function build_soap_fault(fault_code, fault_string, detail)
    local xml = '<?xml version="1.0" encoding="UTF-8"?>\n'
    xml = xml .. '<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">\n'
    xml = xml .. '  <soap:Body>\n'
    xml = xml .. '    <soap:Fault>\n'
    xml = xml .. '      <faultcode>' .. (fault_code or "soap:Server") .. '</faultcode>\n'
    xml = xml .. '      <faultstring>' .. (fault_string or "Internal Server Error") .. '</faultstring>\n'
    if detail then
        xml = xml .. '      <detail>' .. detail .. '</detail>\n'
    end
    xml = xml .. '    </soap:Fault>\n'
    xml = xml .. '  </soap:Body>\n'
    xml = xml .. '</soap:Envelope>'
    return xml
end

-- Build a simple SOAP response XML string
local function build_soap_response(operation_name, response_data)
    local xml = '<?xml version="1.0" encoding="UTF-8"?>\n'
    xml = xml .. '<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">\n'
    xml = xml .. '  <soap:Body>\n'
    xml = xml .. '    <' .. operation_name .. 'Response>\n'

    if type(response_data) == "table" then
        for key, value in pairs(response_data) do
            if type(value) == "table" then
                -- Handle array
                for _, item in ipairs(value) do
                    xml = xml .. '      <' .. key .. '>' .. tostring(item) .. '</' .. key .. '>\n'
                end
            else
                xml = xml .. '      <' .. key .. '>' .. tostring(value) .. '</' .. key .. '>\n'
            end
        end
    elseif response_data then
        xml = xml .. '      ' .. tostring(response_data) .. '\n'
    end

    xml = xml .. '    </' .. operation_name .. 'Response>\n'
    xml = xml .. '  </soap:Body>\n'
    xml = xml .. '</soap:Envelope>'
    return xml
end

